mapper.select:
SELECT COUNT(*)
FROM reservations rv
WHERE rv.accommodation_id = #{accommodationId}
  AND rv.status IN ('PENDING', 'CONFIRMED')
  AND rv.check_out_date > #{businessDate}

SELECT COUNT(*)
FROM reservations rv
WHERE rv.room_type_id = #{roomTypeId}
  AND rv.status IN ('PENDING', 'CONFIRMED')
  AND rv.check_out_date > #{businessDate}
